import React, { useState, useEffect } from 'react';
import axios from 'axios';

function Marquee() {
  const [streamTitle, setStreamTitle] = useState('Loading...');

  useEffect(() => {
    const fetchStreamTitle = async () => {
      try {
        const response = await axios.get('http://your-azuracast-site.example.com/api/nowplaying/koska_radio');
        const title = response.data.now_playing.song.title;
        setStreamTitle(title);
      } catch (error) {
        console.error('Error fetching stream title:', error);
        // Handle the error as needed
      }
    };

    // Fetch the stream title initially and then set up a refresh interval
    fetchStreamTitle();

    const refreshInterval = setInterval(() => {
      fetchStreamTitle();
    }, 15000); // Refresh every 15 seconds (adjust this interval as needed)

    return () => {
      clearInterval(refreshInterval); // Clear the interval when the component unmounts
    };
  }, []);

  return <marquee>{streamTitle}</marquee>;
}

export default Marquee;
